# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import requests

app = Flask(__name__)

ES_HOST = 'localhost'
ES_PORT = 9200
INDEX_NAME = 'products'

@app.route('/api/search', methods=['GET'])
def search_products():
    q = request.args.get('q')
    if not q:
        return jsonify({'error': 'missing query parameter'}), 400
    
    try:
        es_url = f'http://{ES_HOST}:{ES_PORT}/{INDEX_NAME}/_search'
        query_body = {
            "query": {
                "multi_match": {
                    "fields": ["name^5", "description"],
                    "query": q,
                    "fuzziness": 2
                }
            },
            "size": 10,
            "from": 0
        }
        
        response = requests.get(es_url, json=query_body)
        data = response.json()
        results = data['hits']['hits']
        
        result_list = []
        for hit in results:
            product = {
                'id': hit['_source']['id'],
                'name': hit['_source']['name'],
                'price': hit['_source']['price'],
                'description': hit['_source']['description']
            }
            result_list.append(product)
        
        return jsonify(result_list), 200
    
    except requests.exceptions.RequestException as e:
        print(f'Error making request to Elasticsearch: {e}')
        return jsonify({'error': 'failed to connect to elasticsearch'}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)